def gen(rng, size):
    n = max(2, min(size, 1000))
    key = rng.randint(1, 1000)
    favored = rng.randint(1, 1000)
    nums = []
    for _ in range(n):
        nums.append(rng.randint(1, 1000))
    # force key to appear and make favored the clear most frequent follower
    for i in range(0, n - 1, 2):
        if rng.random() < 0.6:
            nums[i] = key
            nums[i + 1] = favored
    if key not in nums[:-1]:
        nums[0] = key
        nums[1] = favored
    return [nums, key]

