var mostFrequent = function(nums, key) {
    const cnt = new Map();
    for (let i = 0; i < nums.length - 1; i++) {
        if (nums[i] === key) {
            cnt.set(nums[i + 1], (cnt.get(nums[i + 1]) || 0) + 1);
        }
    }
    let best = null, bestCount = -1;
    for (const [val, c] of cnt) {
        if (c > bestCount) {
            bestCount = c;
            best = val;
        }
    }
    return best;
};
